import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import "../styles/ProfilePage.css";

function ProfilePage() {
  let [username, setUsername] = useState("");
  let [email, setEmail] = useState("");
  let [newPassword, setNewPassword] = useState("");
  let [confirmPassword, setConfirmPassword] = useState("");
  let [loading, setLoading] = useState(true);
  let [saving, setSaving] = useState(false);
  let [errors, setErrors] = useState([]);
  let [message, setMessage] = useState("");

  let navigate = useNavigate();

  useEffect(() => {
    let loggedUser = localStorage.getItem("loggedUser");

    if (!loggedUser) {
      navigate("/logowanie");
      return;
    }

    let user = JSON.parse(loggedUser);

    fetch("http://localhost:5000/api/profil/" + user.id)
      .then((response) => response.json())
      .then((data) => {
        if (data.error) {
          setErrors([data.error]);
          setLoading(false);
          return;
        }

        setUsername(data.nazwa_uzytkownika || "");
        setEmail(data.email || "");
        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setErrors(["Nie udało się pobrać danych profilu."]);
        setLoading(false);
      });
  }, [navigate]);

  async function handleSubmit(e) {
    e.preventDefault();

    setErrors([]);
    setMessage("");

    let localErrors = [];

    if (!username.trim()) {
      localErrors.push("Nazwa użytkownika jest wymagana.");
    }

    if (newPassword && newPassword !== confirmPassword) {
      localErrors.push("Nowe hasła nie są takie same.");
    }

    if (localErrors.length > 0) {
      setErrors(localErrors);
      return;
    }

    try {
      let loggedUser = localStorage.getItem("loggedUser");

      if (!loggedUser) {
        navigate("/logowanie");
        return;
      }

      let user = JSON.parse(loggedUser);

      setSaving(true);

      let response = await fetch("http://localhost:5000/api/profil/" + user.id, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          nazwa_uzytkownika: username,
          nowe_haslo: newPassword
        })
      });

      let data = await response.json();

      if (!response.ok) {
        setErrors(data.errors || ["Nie udało się zapisać zmian."]);
        setSaving(false);
        return;
      }

      localStorage.setItem("loggedUser", JSON.stringify(data.user));
      window.dispatchEvent(new Event("authChanged"));

      setMessage("Profil został zapisany.");
      setNewPassword("");
      setConfirmPassword("");
      setSaving(false);
    } catch (error) {
      console.log(error);
      setErrors(["Nie udało się połączyć z serwerem."]);
      setSaving(false);
    }
  }

  return (
    <div className="app">
      <Navbar />

      <main className="profile-page">
        <section className="profile-hero">
          <div className="container">
            <h1>Twój profil</h1>
            <p>Zarządzaj nazwą użytkownika i hasłem swojego konta.</p>
          </div>
        </section>

        <section className="section">
          <div className="container">
            {loading ? (
              <p>Ładowanie profilu...</p>
            ) : (
              <div className="profile-card">
                <div className="profile-card-header">
                  <div className="profile-avatar">
                    {username?.charAt(0)?.toUpperCase() || "U"}
                  </div>

                  <div>
                    <h2>Ustawienia konta</h2>
                    <p>Edytuj swoje dane logowania.</p>
                  </div>
                </div>

                <form className="profile-form" onSubmit={handleSubmit}>
                  <div className="profile-form-group">
                    <label>Nazwa użytkownika</label>
                    <input
                      type="text"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      placeholder="Wpisz nazwę użytkownika"
                    />
                  </div>

                  <div className="profile-form-group">
                    <label>Adres e-mail</label>
                    <input type="email" value={email} disabled />
                  </div>

                  <div className="profile-form-group">
                    <label>Nowe hasło</label>
                    <input
                      type="password"
                      value={newPassword}
                      onChange={(e) => setNewPassword(e.target.value)}
                      placeholder="Wpisz nowe hasło"
                    />
                  </div>

                  <div className="profile-form-group">
                    <label>Powtórz nowe hasło</label>
                    <input
                      type="password"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      placeholder="Powtórz nowe hasło"
                    />
                  </div>

                  {errors.length > 0 && (
                    <div className="profile-error-box">
                      {errors.map((error, index) => (
                        <p key={index} className="profile-error-message">
                          {error}
                        </p>
                      ))}
                    </div>
                  )}

                  {message && <p className="profile-success-message">{message}</p>}

                  <div className="profile-actions">
                    <button type="submit" className="profile-save-btn" disabled={saving}>
                      {saving ? "Zapisywanie..." : "Zapisz zmiany"}
                    </button>
                  </div>
                </form>
              </div>
            )}
          </div>
        </section>
      </main>

      <Footer />
    </div>
  );
}

export default ProfilePage;
